#include <iostream>
using namespace std;
int main() {
    int n, m;
    cin >> n >> m;
    int a[1000], b[1000], c[2000];
    for (int i = 0; i < n; i++) cin >> a[i];
    for (int i = 0; i < m; i++) cin >> b[i];
    int i = 0, j = 0, k = 0;
    while (i < n && j < m) {
        if (a[i] <= b[j]) c[k++] = a[i++];
        else c[k++] = b[j++];
    }
    while (i < n) c[k++] = a[i++];
    while (j < m) c[k++] = b[j++];
    for (int i = 0; i < k; i++) cout << c[i] << " ";
    cout << endl;
    return 0;
}

#include <iostream>
using namespace std;
int main() {
    int n;
    cin >> n;
    int mat[100][100];
    for (int i = 0; i < n; i++)
        for (int j = 0; j < n; j++)
            cin >> mat[i][j];
    int primary = 0, secondary = 0;
    for (int i = 0; i < n; i++) {
        primary += mat[i][i];
        secondary += mat[i][n - 1 - i];
    }
    int total = primary + secondary;
    if (n % 2 == 1) total -= mat[n/2][n/2];
    cout << "Primary diagonal sum: " << primary << endl;
    cout << "Secondary diagonal sum: " << secondary << endl;
    cout << "Total (without double-counting center): " << total << endl;
    return 0;
}

